entry.content:
@font-face {
  font-family: 'MapleMonoCN';
  src: url('../fonts/MapleMono-NF-CN-Regular.ttf') format('truetype');
  font-display: swap;
}

:root {
  --blog-accent: #2563eb;
  --blog-accent-soft: #dbeafe;
  --blog-border: #cbd5e1;
  --blog-surface: #ffffff;
  --blog-text: #1e293b;
  --blog-muted: #64748b;
}

body {
  background:
    radial-gradient(circle at top right, rgba(37, 99, 235, 0.12), transparent 24%),
    linear-gradient(180deg, #f8fafc 0%, #eff6ff 100%);
}

.index-card {
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 24px;
  padding: 1rem;
  background: rgba(255, 255, 255, 0.82);
  backdrop-filter: blur(12px);
  box-shadow: 0 18px 50px rgba(15, 23, 42, 0.06);
}

.index-card img,
.index-img img {
  border-radius: 18px;
}

.post-content code,
.post-content pre,
code,
pre {
  font-family: 'MapleMonoCN', 'Consolas', monospace;
}

.post-meta,
.index-excerpt,
.post-content {
  color: var(--blog-text);
}

.project-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 1.25rem;
}

.project-card {
  border: 1px solid rgba(148, 163, 184, 0.22);
  border-radius: 20px;
  padding: 1.5rem;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.92), rgba(239, 246, 255, 0.88));
  box-shadow: 0 14px 32px rgba(15, 23, 42, 0.06);
}

.project-card h2 {
  margin-top: 0;
  margin-bottom: 0.75rem;
}

.project-card p,
.project-card li {
  color: var(--blog-muted);
}

.project-card ul {
  padding-left: 1rem;
  margin-bottom: 0;
}

.search-list-title,
.project-card a,
.post-content a {
  color: var(--blog-accent);
}
